import React, { useEffect, useRef, useState } from 'react';
import bgVideo from './assets/bg-video.mp4';
import './App.css';

// ─── DATA ────────────────────────────────────────────────────────────────────

const SERVICES = [
  { num:'01', name:'Web Development', img:'https://images.unsplash.com/photo-1547658719-da2b51169166?w=800&q=75&auto=format&fit=crop', desc:'Scalable web applications built with React, Next.js, and modern frameworks for seamless user experiences.' },
  { num:'02', name:'Android & iOS Apps', img:'https://images.unsplash.com/photo-1512941937669-90a1b58e7e9c?w=800&q=75&auto=format&fit=crop', desc:'Cross-platform mobile solutions using Flutter and React Native, crafted for performance and elegance.' },
  { num:'03', name:'IoT Solutions', img:'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=75&auto=format&fit=crop', desc:'Smart connected systems — GPS tracking, home automation, and industrial control for the modern enterprise.' },
  { num:'04', name:'Backend & DevOps', img:'https://images.unsplash.com/photo-1667372393119-3d4c48d07fc9?w=800&q=75&auto=format&fit=crop', desc:'RESTful APIs, Docker, Kubernetes, and CI/CD pipelines delivering robust, scalable infrastructure.' },
  { num:'05', name:'Digital Marketing', img:'https://images.unsplash.com/photo-1611162617474-5b21e879e113?w=800&q=75&auto=format&fit=crop', desc:'Data-driven SEO, SEM, and social media strategies that drive measurable growth and brand authority.' },
  { num:'06', name:'AI & Automation', img:'https://images.unsplash.com/photo-1677442135703-1787eea5ce01?w=800&q=75&auto=format&fit=crop', desc:'Intelligent automation powered by cutting-edge AI to streamline operations and unlock business potential.' },
];

const PRODUCTS = [
  { tag:'IoT Solutions', title:'Smart Monitoring & Automation', img:'https://images.unsplash.com/photo-1601132359864-c974e79890ac?w=1000&q=80&auto=format&fit=crop', desc:'End-to-end IoT ecosystem connecting physical environments with intelligent digital control.', features:['Home & Industry Automation — smart lighting, EB management, automated door systems','Smart Monitoring System — real-time energy tracking with secure biometric access control','GPS Tracking — location-based automation and live monitoring for enhanced operational control'], reverse:false },
  { tag:'Corporate Suite', title:'Business Automation Platform', img:'https://images.unsplash.com/photo-1497366216548-37526070297c?w=1000&q=80&auto=format&fit=crop', desc:'Unified enterprise platform streamlining HR, finance, and operations in one intelligent ecosystem.', features:['HR functions — employee onboarding, attendance, leave management and performance tracking','Project management — real-time collaboration, deadline monitoring and workflow automation','Financial suite — budgeting, invoicing, expense tracking and integrated order management'], reverse:true },
  { tag:'Web Applications', title:'Capture360, Libro360AI & Property360', img:'https://images.unsplash.com/photo-1460925895917-afdab827c52f?w=1000&q=80&auto=format&fit=crop', desc:'Purpose-built web platforms delivering AI-driven insights across industries.', features:['Capture360 — real-time construction site monitoring, resource tracking, AI-driven analytics','Libro360AI — adaptive learning management with intelligent recruitment and talent analytics','Property360 — automated real estate platform for listings, client engagement and sales ops'], reverse:false },
  { tag:'Mobile Applications', title:'Ecom360, Telematics & Kovais', img:'https://images.unsplash.com/photo-1551650975-87deedd944c3?w=1000&q=80&auto=format&fit=crop', desc:'High-performance mobile solutions engineered for logistics, fleet management, and commerce.', features:['Ecom360 — real-time order tracking, delivery route optimization and fulfillment automation','Thiran Telematics — fleet management with GPS, fuel efficiency analytics and alerts','Kovais — automating customer management, order tracking and service coordination at scale'], reverse:true },
];

const STATS = [
  { to:50, suffix:'+', label:'Projects Completed' },
  { to:3, suffix:'', label:'Technology Partners' },
  { to:30, suffix:'+', label:'Team Members' },
  { to:3, suffix:'+', label:'Years Experience' },
];

// ─── PARTICLE CANVAS ─────────────────────────────────────────────────────────

function ParticleCanvas() {
  const canvasRef = useRef(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    let raf;
    const resize = () => { canvas.width = window.innerWidth; canvas.height = window.innerHeight; };
    resize();
    window.addEventListener('resize', resize);
    const nodes = Array.from({ length: 65 }, () => ({
      x: Math.random() * canvas.width, y: Math.random() * canvas.height,
      vx: (Math.random() - 0.5) * 0.4, vy: (Math.random() - 0.5) * 0.4,
      r: Math.random() * 2 + 0.5, red: Math.random() > 0.6,
    }));
    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      for (let i = 0; i < nodes.length; i++) for (let j = i + 1; j < nodes.length; j++) {
        const dx = nodes[i].x - nodes[j].x, dy = nodes[i].y - nodes[j].y, d = Math.hypot(dx, dy);
        if (d < 130) {
          const a = (1 - d / 130) * 0.15;
          ctx.beginPath(); ctx.moveTo(nodes[i].x, nodes[i].y); ctx.lineTo(nodes[j].x, nodes[j].y);
          ctx.strokeStyle = (nodes[i].red || nodes[j].red) ? `rgba(185,28,28,${a * 2})` : `rgba(80,80,80,${a * 0.7})`;
          ctx.lineWidth = 0.6; ctx.stroke();
        }
      }
      nodes.forEach(n => {
        ctx.beginPath(); ctx.arc(n.x, n.y, n.r, 0, Math.PI * 2);
        ctx.fillStyle = n.red ? 'rgba(220,38,38,0.8)' : 'rgba(130,130,130,0.4)'; ctx.fill();
        n.x += n.vx; n.y += n.vy;
        if (n.x < 0 || n.x > canvas.width) n.vx *= -1;
        if (n.y < 0 || n.y > canvas.height) n.vy *= -1;
      });
      raf = requestAnimationFrame(draw);
    };
    draw();
    return () => { cancelAnimationFrame(raf); window.removeEventListener('resize', resize); };
  }, []);
  return <canvas ref={canvasRef} style={{ position:'fixed', inset:0, zIndex:0, pointerEvents:'none' }} />;
}

// ─── TRAIL CANVAS ─────────────────────────────────────────────────────────────

function TrailCanvas() {
  const canvasRef = useRef(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const REDS = ['#DC2626','#EF4444','#B91C1C','#F87171','#FF3333','#CC0000'];
    const pool = [];
    const resize = () => { canvas.width = window.innerWidth; canvas.height = window.innerHeight; };
    resize(); window.addEventListener('resize', resize);
    const spawnAt = (x, y, count) => {
      for (let i = 0; i < count; i++) {
        const angle = Math.random() * Math.PI * 2, speed = Math.random() * 3.5 + 0.8;
        pool.push({ x, y, vx: Math.cos(angle)*speed, vy: Math.sin(angle)*speed - Math.random()*1.5, w: Math.random()*5+2, h: Math.random()*2.5+1, angle: Math.random()*Math.PI*2, spin:(Math.random()-0.5)*0.18, color: REDS[Math.floor(Math.random()*REDS.length)], alpha:1, decay: Math.random()*0.022+0.012, gravity:0.07 });
      }
    };
    let lx = -999, ly = -999;
    const onMove = e => {
      const dx = e.clientX - lx, dy = e.clientY - ly, d = Math.hypot(dx, dy);
      if (d > 6) { const n = Math.min(Math.ceil(d/5),6); for(let i=0;i<n;i++){const t=i/n;spawnAt(lx+dx*t,ly+dy*t,1);} lx=e.clientX;ly=e.clientY; }
    };
    const onTouch = e => { const t=e.touches[0]; spawnAt(t.clientX,t.clientY,3); };
    window.addEventListener('mousemove', onMove);
    window.addEventListener('touchmove', onTouch, {passive:true});
    let raf;
    const loop = () => {
      ctx.clearRect(0,0,canvas.width,canvas.height); ctx.shadowBlur=0;
      for (let i=pool.length-1;i>=0;i--) {
        const p=pool[i]; p.x+=p.vx; p.y+=p.vy; p.vy+=p.gravity; p.vx*=0.985; p.angle+=p.spin; p.alpha-=p.decay;
        if(p.alpha<=0){pool.splice(i,1);continue;}
        ctx.save(); ctx.globalAlpha=p.alpha; ctx.fillStyle=p.color; ctx.translate(p.x,p.y); ctx.rotate(p.angle); ctx.fillRect(-p.w/2,-p.h/2,p.w,p.h); ctx.restore();
      }
      if(pool.length>500) pool.splice(0,pool.length-500);
      raf=requestAnimationFrame(loop);
    };
    loop();
    return () => { cancelAnimationFrame(raf); window.removeEventListener('mousemove',onMove); window.removeEventListener('resize',resize); };
  }, []);
  return <canvas ref={canvasRef} style={{position:'fixed',inset:0,zIndex:5,pointerEvents:'none'}} />;
}

// ─── COUNTER ──────────────────────────────────────────────────────────────────

function Counter({ to, suffix }) {
  const [val, setVal] = useState(0);
  const ref = useRef(null);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) {
        let v = 0, inc = to / 60;
        const t = setInterval(() => { v += inc; if (v >= to) { setVal(to); clearInterval(t); } else setVal(Math.floor(v)); }, 24);
        obs.disconnect();
      }
    }, { threshold: 0.5 });
    obs.observe(ref.current);
    return () => obs.disconnect();
  }, [to]);
  return <div ref={ref} className="stat-value">{val}{suffix}</div>;
}

// ─── FLOATING SOCIAL BUTTONS ──────────────────────────────────────────────────

function FloatingSocial() {
  return (
    <div className="floating-social">
      <a href="https://www.instagram.com/thiran360ai/" target="_blank" rel="noreferrer" className="float-btn" title="Instagram">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
          <rect x="2" y="2" width="20" height="20" rx="5" ry="5"/>
          <path d="M16 11.37A4 4 0 1 1 12.63 8 4 4 0 0 1 16 11.37z"/>
          <line x1="17.5" y1="6.5" x2="17.51" y2="6.5"/>
        </svg>
      </a>
      <a href="https://www.linkedin.com/in/manickavasagarg" target="_blank" rel="noreferrer" className="float-btn" title="LinkedIn">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
          <path d="M16 8a6 6 0 0 1 6 6v7h-4v-7a2 2 0 0 0-2-2 2 2 0 0 0-2 2v7h-4v-7a6 6 0 0 1 6-6z"/>
          <rect x="2" y="9" width="4" height="12"/>
          <circle cx="4" cy="4" r="2"/>
        </svg>
      </a>
      <a href="mailto:info@thiran360ai.com" className="float-btn" title="Email">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
          <path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"/>
          <polyline points="22,6 12,13 2,6"/>
        </svg>
      </a>
    </div>
  );
}

// ─── NAVBAR ───────────────────────────────────────────────────────────────────

function Navbar({ scrolled }) {
  const scrollTo = id => document.getElementById(id)?.scrollIntoView({ behavior:'smooth' });
  return (
    <nav className={`navbar${scrolled?' scrolled':''}`}>
      <div className="nav-inner">
        <div className="nav-logo" onClick={() => window.scrollTo({top:0,behavior:'smooth'})}>
          <span className="nav-logo-stg">STG</span>
        </div>
        <ul className="nav-menu">
          <li><a onClick={() => scrollTo('services')}>Services</a></li>
          <li><a onClick={() => scrollTo('products')}>Products</a></li>
          <li><a onClick={() => scrollTo('about')}>About</a></li>
          <li><a onClick={() => scrollTo('contact')}>Careers</a></li>
          <li><a className="nav-cta-btn" onClick={() => scrollTo('contact')}>Contact Us</a></li>
        </ul>
      </div>
    </nav>
  );
}

// ─── HERO ─────────────────────────────────────────────────────────────────────

function Hero() {
  const scrollTo = id => document.getElementById(id)?.scrollIntoView({ behavior:'smooth' });
  return (
    <section className="hero" id="home">
      {/* Full-page video background */}
      <div className="hero-video-wrap">
        <video
          className="hero-video"
          src={bgVideo}
          autoPlay
          muted
          loop
          playsInline
        />
        <div className="hero-video-overlay" />
      </div>

      {/* STG floating badges */}
      <div className="hero-stg-floaters">
        {[
          {top:'15%',left:'5%',dur:'4s',delay:'0s',text:'STG'},
          {top:'25%',right:'8%',dur:'6s',delay:'1s',text:'STG'},
          {top:'60%',left:'3%',dur:'5s',delay:'2s',text:'STG'},
          {top:'70%',right:'5%',dur:'4.5s',delay:'0.5s',text:'STG'},
          {top:'40%',left:'50%',dur:'7s',delay:'1.5s',text:'STG'},
          {top:'80%',left:'30%',dur:'5.5s',delay:'3s',text:'STG'},
          {top:'10%',left:'60%',dur:'4s',delay:'0.8s',text:'THIRAN360AI'},
          {top:'50%',right:'15%',dur:'6.5s',delay:'2.5s',text:'THIRAN360AI'},
        ].map((f,i) => (
          <span key={i} className="hero-stg-float" style={{top:f.top,left:f.left,right:f.right,animationDuration:f.dur,animationDelay:f.delay}}>{f.text}</span>
        ))}
      </div>

      <div className="hero-content">
        <div className="hero-stg-row">
          <div className="hero-stg-badge antigrav">STG</div>
          <div className="hero-stg-badge antigrav-2">THIRAN360AI</div>
          <div className="hero-stg-badge antigrav-3">STG · STG · STG</div>
        </div>
        <div className="hero-eyebrow">
          <div className="hero-eyebrow-line" />
          <span className="hero-eyebrow-text">Global Software Powerhouse</span>
        </div>
        <h1 className="hero-title">
          We Build
          <span className="hero-title-bold">Digital</span>
          <span className="hero-title-accent">Experiences.</span>
        </h1>
        <p className="hero-subtitle">Crafting innovative technology solutions that transform businesses and elevate user experiences — powered by intelligence, built for the future.</p>
        <div className="hero-actions">
          <button className="btn-red" onClick={() => scrollTo('services')}>Explore Our Work <span>→</span></button>
          <button className="btn-ghost" onClick={() => scrollTo('contact')}>Get In Touch</button>
        </div>
      </div>
      <div className="hero-scroll-indicator">
        <div className="hero-scroll-line" />
        <span className="hero-scroll-text">Scroll</span>
      </div>
    </section>
  );
}

// ─── SERVICES ─────────────────────────────────────────────────────────────────

function Services() {
  return (
    <section className="section" id="services">
      <div className="container">
        <div className="services-header">
          <div>
            <div className="stg-tag">STG · Thiran360AI</div>
            <div className="section-label"><span className="section-label-line" /><span className="section-label-text">What We Do</span></div>
            <h2 className="section-heading">Our <strong>Services</strong></h2>
          </div>
          <p className="section-subtext">Comprehensive technology solutions tailored to every dimension of your business — from concept to deployment and beyond.</p>
        </div>
        <div className="services-grid">
          {SERVICES.map((s,i) => (
            <div key={i} className="service-item" style={{animationDelay:`${i*0.08}s`}}>
              <span className="service-stg">STG</span>
              <img src={s.img} alt={s.name} className="service-item-img" loading="lazy" />
              <div className="service-number">{s.num}</div>
              <div className="service-name">{s.name}</div>
              <p className="service-desc">{s.desc}</p>
              <div className="service-arrow">→</div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

// ─── PRODUCTS ─────────────────────────────────────────────────────────────────

function Products() {
  return (
    <section className="section section-alt" id="products">
      <div className="container" style={{marginBottom:'56px'}}>
        <div className="stg-tag">STG · Thiran360AI</div>
        <div className="section-label"><span className="section-label-line" /><span className="section-label-text">What We've Built</span></div>
        <h2 className="section-heading">Our <strong>Products</strong></h2>
      </div>
      {PRODUCTS.map((p,i) => (
        <div key={i} className={`product-row${p.reverse?' reverse':''}`}>
          <div className="product-image-wrap">
            <img src={p.img} alt={p.title} loading="lazy" />
            <div className="product-image-overlay" />
            <span className="product-category-badge">{p.tag}</span>
          </div>
          <div className="product-body">
            <span className="product-tag">{p.tag}</span>
            <h3 className="product-title">{p.title}</h3>
            <p className="product-desc">{p.desc}</p>
            <ul className="product-features">
              {p.features.map((f,j) => <li key={j}><span className="feature-dot"/>{f}</li>)}
            </ul>
          </div>
        </div>
      ))}
    </section>
  );
}

// ─── ABOUT ────────────────────────────────────────────────────────────────────

function About() {
  return (
    <section className="section" id="about">
      <div className="container">
        <div className="stg-tag">STG · Thiran360AI</div>
        <div className="section-label" style={{marginBottom:'56px'}}><span className="section-label-line"/><span className="section-label-text">Who We Are</span></div>
        <div className="about-grid">
          <div className="about-image-stack">
            <img src="https://images.unsplash.com/photo-1522071820081-009f0129c71c?w=1000&q=80&auto=format&fit=crop" alt="Team" className="about-img-main" loading="lazy"/>
            <img src="https://images.unsplash.com/photo-1559136555-9303baea8ebd?w=600&q=75&auto=format&fit=crop" alt="Innovation" className="about-img-accent" loading="lazy"/>
            <div className="about-img-badge"><div className="about-img-badge-num">360°</div><div className="about-img-badge-txt">Holistic Approach</div></div>
          </div>
          <div className="about-text">
            <h2 className="section-heading">The <strong>Story</strong> Behind<br/>Our Name</h2>
            <p className="section-subtext" style={{marginTop:'16px'}}>Three words, one powerful mission — Thiran, 360, AI — each carrying deep meaning about how we build, who we serve, and where we're headed.</p>
            {[
              {num:'01', h:'Thiran — Talent & Ability', t:'The name symbolizes the innate talent and ability that defines every member of our team. We approach every project with precision, creativity, and unwavering craft.'},
              {num:'02', h:'360 — Holistic Vision', t:"We consider every angle. Our 360 approach means no detail is overlooked, no perspective ignored — delivering solutions that are truly complete."},
              {num:'03', h:'AI — The Future Now', t:"Artificial intelligence isn't tomorrow's technology for us — it's the foundation of everything we build today, creating experiences that are forward-thinking and transformative."},
            ].map((s,i) => (
              <div key={i} className="about-story-item">
                <div className="about-story-num">{s.num}</div>
                <h4 className="about-story-heading">{s.h}</h4>
                <p className="about-story-text">{s.t}</p>
              </div>
            ))}
          </div>
        </div>

        {/* STATS */}
        <div className="stats-bar" style={{marginTop:'60px'}}>
          {STATS.map((s,i) => (
            <div key={i} className="stat-item">
              <Counter to={s.to} suffix={s.suffix}/>
              <div className="stat-label">{s.label}</div>
            </div>
          ))}
        </div>

        {/* VALUES */}
        <div style={{marginTop:'80px'}}>
          <div className="stg-tag">STG · Core Values</div>
          <div className="section-label" style={{marginBottom:'40px'}}><span className="section-label-line"/><span className="section-label-text">Our Core Values</span></div>
          <div className="values-grid">
            {[
              {icon:'🎯', h:'Vision', t:'To become a global leader in intelligent digital transformation — empowering industries through AI, design, and relentless innovation.'},
              {icon:'🚀', h:'Mission', t:'To craft future-ready experiences by blending creativity, technology, and strategy — driven by purpose, fueled by passion.'},
              {icon:'💡', h:'Innovation', t:"We constantly push boundaries, harnessing emerging technologies to shape intelligent solutions for tomorrow's most complex challenges."},
            ].map((v,i) => (
              <div key={i} className="value-card">
                <div className="value-icon-wrap">{v.icon}</div>
                <h3 className="value-heading">{v.h}</h3>
                <p className="value-text">{v.t}</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

// ─── PARTNERS ────────────────────────────────────────────────────────────────

function Partners() {
  return (
    <div className="partners-strip">
      <div className="partners-inner">
        <span className="partners-label">Strategic Partners</span>
        <div className="partners-divider"/>
        <div className="partner-items">
          {[{n:'AWS',t:'Advanced Technology Partner'},{n:'Azure',t:'Cloud Solution Provider'},{n:'Oracle',t:'Gold Level Partner'}].map((p,i)=>(
            <div key={i} className="partner-item"><div className="partner-name">{p.n}</div><div className="partner-tier">{p.t}</div></div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ─── CONTACT ──────────────────────────────────────────────────────────────────

function Contact() {
  const [sent, setSent] = useState(false);
  const handleSubmit = e => { e.preventDefault(); setSent(true); setTimeout(()=>setSent(false),4000); };
  return (
    <section className="section section-alt" id="contact">
      <div className="container">
        <div className="stg-tag">STG · Thiran360AI</div>
        <div className="section-label" style={{marginBottom:'56px'}}><span className="section-label-line"/><span className="section-label-text">Get In Touch</span></div>
        <div className="contact-layout">
          {/* FORM */}
          <div className="contact-form-wrap">
            <h3 className="contact-form-title">Send Us a Message</h3>
            <form onSubmit={handleSubmit}>
              <div className="form-row">
                <div className="form-field"><label className="form-label">First Name</label><input className="form-control" type="text" placeholder="John" required/></div>
                <div className="form-field"><label className="form-label">Last Name</label><input className="form-control" type="text" placeholder="Doe" required/></div>
              </div>
              <div className="form-row">
                <div className="form-field"><label className="form-label">Email Address</label><input className="form-control" type="email" placeholder="john@company.com" required/></div>
                <div className="form-field"><label className="form-label">Phone Number</label><input className="form-control" type="tel" placeholder="+91 98765 43210"/></div>
              </div>
              <div className="form-field">
                <label className="form-label">Service of Interest</label>
                <select className="form-control">
                  <option value="">Select a service...</option>
                  <option>Web Development</option><option>Mobile App Development</option><option>IoT Solutions</option><option>Backend & DevOps</option><option>Digital Marketing</option><option>AI & Automation</option>
                </select>
              </div>
              <div className="form-field"><label className="form-label">Your Message</label><textarea className="form-control" rows="5" placeholder="Tell us about your project..." required/></div>
              <button type="submit" className={`form-submit${sent?' sent':''}`}>{sent?'✓ Message Sent Successfully!':'Send Message →'}</button>
            </form>
          </div>

          {/* INFO */}
          <div className="contact-info-side">
            <h2 className="contact-info-heading">Let's Build<br/>Something <strong>Extraordinary</strong></h2>
            <p className="contact-info-text">Have a project in mind? Our team of engineers, designers, and strategists is ready to transform your vision into a powerful digital reality.</p>
            <div className="contact-detail-list">
              <div className="contact-detail-item"><div className="contact-detail-icon">✉</div><span>info@thiran360ai.com</span></div>
